-- Day 7 (Web Applications) — 15 per-player dynamic challenges.
-- 4 easy + 4 medium logic/CS puzzles, 4 hard web-app-security challenges, and a
-- 3-challenge DANGER zone (custom-VM reversing / many-time-pad / Z3 constraints).
-- Generated by scripts/gen-day7-webapps.py. Artifacts live in public/challenges/day7/
-- and contain NO flag string; verify_challenge_answer mints a per-player KGSP{...} flag
-- only on a correct recovered answer, so pasting a prompt into an AI yields nothing.
-- UPSERT-ONLY: never deletes a challenge row (see migrations/README.md rule #1), so
-- re-applying is safe and preserves each row's per-deploy `secret`.
-- Day 7 stays LOCKED (is_open=false) and code-gated (WEBHACK-2026) until go-live.
begin;

insert into public.days (day, title, subtitle, is_open, sort_order, is_rest, requires_code, is_completed)
values (7, '🌐 Day 7 — Web Applications',
  'Logic & CS warm-ups (redirects, encodings, LCGs, cycle detection, bit ops) then serious web-app security: blind SQLi, request smuggling, SSTI, prototype pollution — and a DANGER zone (custom-VM reversing, many-time-pad cryptanalysis, a Z3 constraint system)',
  false, 7, false, true, false)
on conflict (day) do update set title = excluded.title, subtitle = excluded.subtitle,
  requires_code = true;
insert into public.day_codes (day, code) values (7, 'WEBHACK-2026') on conflict (day) do nothing;

insert into public.challenges (id, title, category, difficulty, points, first_blood_bonus, sort_order, prompt, asset_url, action_url, num_hints, day, is_extra, is_dynamic) values (
  'd7_redirect_chain', 'Redirect Roulette', 'Web Logic', 'easy', 150, 50, 701,
  '[Logic puzzle — reading + a little scripting] A crawl of a web API dumped every route''s response. Each 302 points to the next route via its Location header; exactly one route returns 200 OK and carries the prize in an X-Flag-Data header. Some routes are decoys (dead ends, loops). Start at /entry, follow the chain of redirects to the single 200, and base64-decode its body. Submit the decoded plaintext (lowercase, underscores).',
  '/challenges/day7/redirect-map.txt', '/challenge/verify/d7_redirect_chain', 1, 7, false, true)
on conflict (id) do update set title=excluded.title, category=excluded.category,
  difficulty=excluded.difficulty, points=excluded.points, first_blood_bonus=excluded.first_blood_bonus,
  sort_order=excluded.sort_order, prompt=excluded.prompt, asset_url=excluded.asset_url,
  action_url=excluded.action_url, num_hints=excluded.num_hints, day=excluded.day,
  is_extra=excluded.is_extra, is_dynamic=excluded.is_dynamic;
insert into public.challenge_answer_keys (challenge_id, answer, secret, live_material) values ('d7_redirect_chain', 'follow_the_redirects', encode(extensions.gen_random_bytes(16),'hex'), null)
  on conflict (challenge_id) do update set answer = excluded.answer, live_material = excluded.live_material;
insert into public.challenge_hints (challenge_id, hint_number, body, penalty) values ('d7_redirect_chain', 1, 'Treat it as a linked list: /entry -> its Location -> that route''s Location -> ... until a 200. Ignore /trap, /loop*, /old, /mirror. The 200 body is base64.', 40)
  on conflict (challenge_id, hint_number) do update set body = excluded.body, penalty = excluded.penalty;

insert into public.challenges (id, title, category, difficulty, points, first_blood_bonus, sort_order, prompt, asset_url, action_url, num_hints, day, is_extra, is_dynamic) values (
  'd7_base_soup', 'Encoding Soup', 'Encoding', 'easy', 150, 50, 702,
  '[Logic puzzle — encoding] A token was wrapped in four stacked encodings — base64, ROT13, base32 and hex — but the order isn''t given. Each layer''s alphabet reveals what it is, so peel them one at a time (a tool like CyberChef helps) until readable text falls out. Submit the plaintext (lowercase, underscores).',
  '/challenges/day7/encoding-soup.txt', '/challenge/verify/d7_base_soup', 1, 7, false, true)
on conflict (id) do update set title=excluded.title, category=excluded.category,
  difficulty=excluded.difficulty, points=excluded.points, first_blood_bonus=excluded.first_blood_bonus,
  sort_order=excluded.sort_order, prompt=excluded.prompt, asset_url=excluded.asset_url,
  action_url=excluded.action_url, num_hints=excluded.num_hints, day=excluded.day,
  is_extra=excluded.is_extra, is_dynamic=excluded.is_dynamic;
insert into public.challenge_answer_keys (challenge_id, answer, secret, live_material) values ('d7_base_soup', 'layers_all_the_way_down', encode(extensions.gen_random_bytes(16),'hex'), null)
  on conflict (challenge_id) do update set answer = excluded.answer, live_material = excluded.live_material;
insert into public.challenge_hints (challenge_id, hint_number, body, penalty) values ('d7_base_soup', 1, 'The outermost layer here is hex (only 0-9a-f). Under it is base32 (A-Z, 2-7). Keep peeling: the next looks like shifted text (ROT13), and the last is base64.', 40)
  on conflict (challenge_id, hint_number) do update set body = excluded.body, penalty = excluded.penalty;

insert into public.challenges (id, title, category, difficulty, points, first_blood_bonus, sort_order, prompt, asset_url, action_url, num_hints, day, is_extra, is_dynamic) values (
  'd7_checksum_key', 'The Real Key', 'Logic', 'easy', 175, 50, 703,
  '[Logic puzzle — math] Twelve leaked API keys, exactly one authentic. The rule: a key is genuine iff the sum of its 16 hex digits (a=10 ... f=15) is divisible by 13. Compute the digit-sum of each key, find the single one that passes, and submit it exactly (lowercase, 16 hex chars).',
  '/challenges/day7/api-keys.txt', '/challenge/verify/d7_checksum_key', 1, 7, false, true)
on conflict (id) do update set title=excluded.title, category=excluded.category,
  difficulty=excluded.difficulty, points=excluded.points, first_blood_bonus=excluded.first_blood_bonus,
  sort_order=excluded.sort_order, prompt=excluded.prompt, asset_url=excluded.asset_url,
  action_url=excluded.action_url, num_hints=excluded.num_hints, day=excluded.day,
  is_extra=excluded.is_extra, is_dynamic=excluded.is_dynamic;
insert into public.challenge_answer_keys (challenge_id, answer, secret, live_material) values ('d7_checksum_key', '6e695e6f9ab419a1', encode(extensions.gen_random_bytes(16),'hex'), null)
  on conflict (challenge_id) do update set answer = excluded.answer, live_material = excluded.live_material;
insert into public.challenge_hints (challenge_id, hint_number, body, penalty) values ('d7_checksum_key', 1, 'For each key, map every character to a number (0-9, then a=10 ... f=15), add all 16 up, and check sum %% 13 == 0. Only one key satisfies it.', 40)
  on conflict (challenge_id, hint_number) do update set body = excluded.body, penalty = excluded.penalty;

insert into public.challenges (id, title, category, difficulty, points, first_blood_bonus, sort_order, prompt, asset_url, action_url, num_hints, day, is_extra, is_dynamic) values (
  'd7_regex_lock', 'Regex Lock', 'Logic', 'easy', 200, 50, 704,
  '[Logic puzzle — pattern matching] A password policy lists five rules; exactly one of the ten candidate passwords satisfies all of them simultaneously. Check each candidate against every rule (length, character classes, digit count, underscores, exactly one vowel) and submit the single one that passes them all.',
  '/challenges/day7/password-lock.txt', '/challenge/verify/d7_regex_lock', 1, 7, false, true)
on conflict (id) do update set title=excluded.title, category=excluded.category,
  difficulty=excluded.difficulty, points=excluded.points, first_blood_bonus=excluded.first_blood_bonus,
  sort_order=excluded.sort_order, prompt=excluded.prompt, asset_url=excluded.asset_url,
  action_url=excluded.action_url, num_hints=excluded.num_hints, day=excluded.day,
  is_extra=excluded.is_extra, is_dynamic=excluded.is_dynamic;
insert into public.challenge_answer_keys (challenge_id, answer, secret, live_material) values ('d7_regex_lock', 'd4rk_f0e_2026', encode(extensions.gen_random_bytes(16),'hex'), null)
  on conflict (challenge_id) do update set answer = excluded.answer, live_material = excluded.live_material;
insert into public.challenge_hints (challenge_id, hint_number, body, penalty) values ('d7_regex_lock', 1, 'Go rule by rule and eliminate. Watch the two strict ones: exactly 13 characters, and exactly ONE vowel (a/e/i/o/u) in the whole string — those knock out almost everything.', 40)
  on conflict (challenge_id, hint_number) do update set body = excluded.body, penalty = excluded.penalty;

insert into public.challenges (id, title, category, difficulty, points, first_blood_bonus, sort_order, prompt, asset_url, action_url, num_hints, day, is_extra, is_dynamic) values (
  'd7_cookie_lcg', 'Predictable Sessions', 'Crypto / Logic', 'medium', 275, 50, 705,
  '[Logic puzzle — modular arithmetic] A site mints 32-bit session tokens with a Linear Congruential Generator, token_next = (A*token_prev + C) mod 2^32, with A and C secret. From five consecutive captured tokens, solve for A and C (modular inverse mod 2^32), then step the generator one step BACKWARD to recover the admin''s previous token t0. Submit t0 as 8 lowercase hex digits.',
  '/challenges/day7/session-tokens.txt', '/challenge/verify/d7_cookie_lcg', 1, 7, false, true)
on conflict (id) do update set title=excluded.title, category=excluded.category,
  difficulty=excluded.difficulty, points=excluded.points, first_blood_bonus=excluded.first_blood_bonus,
  sort_order=excluded.sort_order, prompt=excluded.prompt, asset_url=excluded.asset_url,
  action_url=excluded.action_url, num_hints=excluded.num_hints, day=excluded.day,
  is_extra=excluded.is_extra, is_dynamic=excluded.is_dynamic;
insert into public.challenge_answer_keys (challenge_id, answer, secret, live_material) values ('d7_cookie_lcg', '9e3779b1', encode(extensions.gen_random_bytes(16),'hex'), null)
  on conflict (challenge_id) do update set answer = excluded.answer, live_material = excluded.live_material;
insert into public.challenge_hints (challenge_id, hint_number, body, penalty) values ('d7_cookie_lcg', 1, 'A = (t3-t2)*inv(t2-t1) mod 2^32, then C = t2 - A*t1. Step back: t0 = (t1-C)*inv(A) mod 2^32. In Python, inv(x) is pow(x,-1,2**32).', 40)
  on conflict (challenge_id, hint_number) do update set body = excluded.body, penalty = excluded.penalty;

insert into public.challenges (id, title, category, difficulty, points, first_blood_bonus, sort_order, prompt, asset_url, action_url, num_hints, day, is_extra, is_dynamic) values (
  'd7_state_cycle', 'The Long Loop', 'CS Logic', 'medium', 300, 50, 706,
  '[Logic puzzle — cycle detection] A register is updated by register = (register^2 + register + 1) mod 65521, starting at 12345, exactly one TRILLION times. Brute force is impossible, but the state space is only 65521 values, so the walk enters a cycle. Detect the tail length mu and cycle length lambda from the seed, then compute the state after (10^12) steps with modular arithmetic. Submit the final value as a decimal number.',
  '/challenges/day7/long-loop.txt', '/challenge/verify/d7_state_cycle', 1, 7, false, true)
on conflict (id) do update set title=excluded.title, category=excluded.category,
  difficulty=excluded.difficulty, points=excluded.points, first_blood_bonus=excluded.first_blood_bonus,
  sort_order=excluded.sort_order, prompt=excluded.prompt, asset_url=excluded.asset_url,
  action_url=excluded.action_url, num_hints=excluded.num_hints, day=excluded.day,
  is_extra=excluded.is_extra, is_dynamic=excluded.is_dynamic;
insert into public.challenge_answer_keys (challenge_id, answer, secret, live_material) values ('d7_state_cycle', '45945', encode(extensions.gen_random_bytes(16),'hex'), null)
  on conflict (challenge_id) do update set answer = excluded.answer, live_material = excluded.live_material;
insert into public.challenge_hints (challenge_id, hint_number, body, penalty) values ('d7_state_cycle', 1, 'Iterate from the seed, recording the step index each state is first seen, until a state repeats: that gives mu (tail) and lambda (cycle). The answer state = iterate mu + ((10^12 - mu) mod lambda) steps from the seed.', 40)
  on conflict (challenge_id, hint_number) do update set body = excluded.body, penalty = excluded.penalty;

insert into public.challenges (id, title, category, difficulty, points, first_blood_bonus, sort_order, prompt, asset_url, action_url, num_hints, day, is_extra, is_dynamic) values (
  'd7_json_smuggle', 'Parser Games', 'Web Logic', 'medium', 275, 50, 707,
  '[Logic puzzle — parser differential] A gateway and a backend parse the same JSON body with libraries that disagree on duplicate keys: the gateway keeps the FIRST value of a repeated key, the backend keeps the LAST. A request sends role twice — ''user'' then ''admin''. Reason out which role the BACKEND acts on, then base64-decode the matching token from the response. Submit the plaintext (lowercase, underscores).',
  '/challenges/day7/parser-games.txt', '/challenge/verify/d7_json_smuggle', 1, 7, false, true)
on conflict (id) do update set title=excluded.title, category=excluded.category,
  difficulty=excluded.difficulty, points=excluded.points, first_blood_bonus=excluded.first_blood_bonus,
  sort_order=excluded.sort_order, prompt=excluded.prompt, asset_url=excluded.asset_url,
  action_url=excluded.action_url, num_hints=excluded.num_hints, day=excluded.day,
  is_extra=excluded.is_extra, is_dynamic=excluded.is_dynamic;
insert into public.challenge_answer_keys (challenge_id, answer, secret, live_material) values ('d7_json_smuggle', 'last_key_wins', encode(extensions.gen_random_bytes(16),'hex'), null)
  on conflict (challenge_id) do update set answer = excluded.answer, live_material = excluded.live_material;
insert into public.challenge_hints (challenge_id, hint_number, body, penalty) values ('d7_json_smuggle', 1, 'The gateway allowed it because the FIRST role is ''user''. The backend keeps the LAST duplicate, so it acted as ''admin'' — decode the admin_token.', 40)
  on conflict (challenge_id, hint_number) do update set body = excluded.body, penalty = excluded.penalty;

insert into public.challenges (id, title, category, difficulty, points, first_blood_bonus, sort_order, prompt, asset_url, action_url, num_hints, day, is_extra, is_dynamic) values (
  'd7_bitwise_safe', 'The Combination', 'CS Logic', 'medium', 300, 50, 708,
  '[Logic puzzle — bitwise] A vault runs a secret 32-bit input through a fixed chain of reversible ops (XORs, 32-bit add/subtract, and bit rotations) and opens only when the result equals a given TARGET. Because every step is reversible there is exactly one input. Invert each operation and apply them in reverse order to recover it. Submit the input as 8 lowercase hex digits.',
  '/challenges/day7/bit-vault.txt', '/challenge/verify/d7_bitwise_safe', 1, 7, false, true)
on conflict (id) do update set title=excluded.title, category=excluded.category,
  difficulty=excluded.difficulty, points=excluded.points, first_blood_bonus=excluded.first_blood_bonus,
  sort_order=excluded.sort_order, prompt=excluded.prompt, asset_url=excluded.asset_url,
  action_url=excluded.action_url, num_hints=excluded.num_hints, day=excluded.day,
  is_extra=excluded.is_extra, is_dynamic=excluded.is_dynamic;
insert into public.challenge_answer_keys (challenge_id, answer, secret, live_material) values ('d7_bitwise_safe', 'c0ffee42', encode(extensions.gen_random_bytes(16),'hex'), null)
  on conflict (challenge_id) do update set answer = excluded.answer, live_material = excluded.live_material;
insert into public.challenge_hints (challenge_id, hint_number, body, penalty) values ('d7_bitwise_safe', 1, 'Go bottom-up from TARGET: undo XOR with the same XOR, undo (+k) with (-k), and undo rotate_left(r) with rotate_right(r) (and vice-versa), all mod 2^32.', 40)
  on conflict (challenge_id, hint_number) do update set body = excluded.body, penalty = excluded.penalty;

insert into public.challenges (id, title, category, difficulty, points, first_blood_bonus, sort_order, prompt, asset_url, action_url, num_hints, day, is_extra, is_dynamic) values (
  'd7_sqli_blind', 'Blind Oracle', 'Web / SQLi', 'hard', 375, 50, 709,
  '[Web exploitation — blind SQL injection] A boolean-blind SQL injection dumped a secret one character at a time. The transcript logs, per position, a binary search over printable ASCII using ASCII(SUBSTRING(secret,pos,1)) > N comparisons and their TRUE/FALSE results. Replay each position''s binary search to pin down every character, then read the full secret. Submit it (lowercase, underscores).',
  '/challenges/day7/blind-sqli-log.txt', '/challenge/verify/d7_sqli_blind', 1, 7, false, true)
on conflict (id) do update set title=excluded.title, category=excluded.category,
  difficulty=excluded.difficulty, points=excluded.points, first_blood_bonus=excluded.first_blood_bonus,
  sort_order=excluded.sort_order, prompt=excluded.prompt, asset_url=excluded.asset_url,
  action_url=excluded.action_url, num_hints=excluded.num_hints, day=excluded.day,
  is_extra=excluded.is_extra, is_dynamic=excluded.is_dynamic;
insert into public.challenge_answer_keys (challenge_id, answer, secret, live_material) values ('d7_sqli_blind', 'admin_db_pass_2026', encode(extensions.gen_random_bytes(16),'hex'), null)
  on conflict (challenge_id) do update set answer = excluded.answer, live_material = excluded.live_material;
insert into public.challenge_hints (challenge_id, hint_number, body, penalty) values ('d7_sqli_blind', 1, 'For one position: start with the range 32..126. TRUE for ''> N'' means the char is above N (set low = N+1); FALSE means it''s N or below (set high = N). When the range collapses to a single value, that''s the ASCII code of the character.', 40)
  on conflict (challenge_id, hint_number) do update set body = excluded.body, penalty = excluded.penalty;

insert into public.challenges (id, title, category, difficulty, points, first_blood_bonus, sort_order, prompt, asset_url, action_url, num_hints, day, is_extra, is_dynamic) values (
  'd7_smuggle', 'Desync', 'Web / Smuggling', 'hard', 400, 50, 710,
  '[Web exploitation — HTTP request smuggling] A CL.TE desync between a front-end proxy (Content-Length) and a back-end (chunked) let an attacker prepend a smuggled prefix to the next visitor''s request, capturing that victim''s headers into a stored comment. Read the capture, understand where the victim''s request got glued on, extract their session cookie, base64-decode it, and submit the plaintext (lowercase, underscores).',
  '/challenges/day7/smuggle-capture.txt', '/challenge/verify/d7_smuggle', 1, 7, false, true)
on conflict (id) do update set title=excluded.title, category=excluded.category,
  difficulty=excluded.difficulty, points=excluded.points, first_blood_bonus=excluded.first_blood_bonus,
  sort_order=excluded.sort_order, prompt=excluded.prompt, asset_url=excluded.asset_url,
  action_url=excluded.action_url, num_hints=excluded.num_hints, day=excluded.day,
  is_extra=excluded.is_extra, is_dynamic=excluded.is_dynamic;
insert into public.challenge_answer_keys (challenge_id, answer, secret, live_material) values ('d7_smuggle', 'session_stolen_by_desync', encode(extensions.gen_random_bytes(16),'hex'), null)
  on conflict (challenge_id) do update set answer = excluded.answer, live_material = excluded.live_material;
insert into public.challenge_hints (challenge_id, hint_number, body, penalty) values ('d7_smuggle', 1, 'The back-end treated the chunked body as ending at ''0'', so ''POST /comment...'' started the next request and the victim''s real ''GET /account'' (with Cookie: session=...) got appended and stored. That session value is base64.', 40)
  on conflict (challenge_id, hint_number) do update set body = excluded.body, penalty = excluded.penalty;

insert into public.challenges (id, title, category, difficulty, points, first_blood_bonus, sort_order, prompt, asset_url, action_url, num_hints, day, is_extra, is_dynamic) values (
  'd7_ssti', 'Template Injection', 'Web / SSTI', 'hard', 400, 50, 711,
  '[Web exploitation — SSTI] A template renders user input as {{ ... }} behind a naive substring blocklist (__class__, __globals__, os, system, mro, ...). The context exposes a Flask-style config dict whose SECRET is base64. From the probe table, find the ONE payload that both survives the blocklist and resolves to the SECRET, decode its base64 output, and submit the plaintext (lowercase, underscores).',
  '/challenges/day7/ssti-sandbox.txt', '/challenge/verify/d7_ssti', 1, 7, false, true)
on conflict (id) do update set title=excluded.title, category=excluded.category,
  difficulty=excluded.difficulty, points=excluded.points, first_blood_bonus=excluded.first_blood_bonus,
  sort_order=excluded.sort_order, prompt=excluded.prompt, asset_url=excluded.asset_url,
  action_url=excluded.action_url, num_hints=excluded.num_hints, day=excluded.day,
  is_extra=excluded.is_extra, is_dynamic=excluded.is_dynamic;
insert into public.challenge_answer_keys (challenge_id, answer, secret, live_material) values ('d7_ssti', 'server_side_template_pwn', encode(extensions.gen_random_bytes(16),'hex'), null)
  on conflict (challenge_id) do update set answer = excluded.answer, live_material = excluded.live_material;
insert into public.challenge_hints (challenge_id, hint_number, body, penalty) values ('d7_ssti', 1, 'The classic gadget chains (__class__.__mro__, __globals__, os.environ) all contain blocked substrings, so they''re rejected. The direct config[''SECRET''] access contains none of the blocked words and reads the SECRET straight out.', 40)
  on conflict (challenge_id, hint_number) do update set body = excluded.body, penalty = excluded.penalty;

insert into public.challenges (id, title, category, difficulty, points, first_blood_bonus, sort_order, prompt, asset_url, action_url, num_hints, day, is_extra, is_dynamic) values (
  'd7_proto_pollution', 'Polluted', 'Web / Prototype Pollution', 'hard', 425, 50, 712,
  '[Web exploitation — prototype pollution] A recursive Node merge() blocklists the top-level ''__proto__'' key but not ''constructor''. An attacker sends constructor.prototype.isAdmin=true, polluting Object.prototype so an unrelated object''s isAdmin check passes and an admin token leaks. Identify the attempt that WORKED, base64-decode its admin_token, and submit the plaintext (lowercase, underscores).',
  '/challenges/day7/proto-pollution.txt', '/challenge/verify/d7_proto_pollution', 1, 7, false, true)
on conflict (id) do update set title=excluded.title, category=excluded.category,
  difficulty=excluded.difficulty, points=excluded.points, first_blood_bonus=excluded.first_blood_bonus,
  sort_order=excluded.sort_order, prompt=excluded.prompt, asset_url=excluded.asset_url,
  action_url=excluded.action_url, num_hints=excluded.num_hints, day=excluded.day,
  is_extra=excluded.is_extra, is_dynamic=excluded.is_dynamic;
insert into public.challenge_answer_keys (challenge_id, answer, secret, live_material) values ('d7_proto_pollution', 'prototype_pollution_pwned', encode(extensions.gen_random_bytes(16),'hex'), null)
  on conflict (challenge_id) do update set answer = excluded.answer, live_material = excluded.live_material;
insert into public.challenge_hints (challenge_id, hint_number, body, penalty) values ('d7_proto_pollution', 1, 'Attempt 1''s ''__proto__'' is skipped by the blocklist. Attempt 2 reaches the prototype via constructor.prototype, so it''s the one that leaks admin_token — decode that base64 value.', 40)
  on conflict (challenge_id, hint_number) do update set body = excluded.body, penalty = excluded.penalty;

insert into public.challenges (id, title, category, difficulty, points, first_blood_bonus, sort_order, prompt, asset_url, action_url, num_hints, day, is_extra, is_dynamic) values (
  'd7_vm', 'The Machine', 'Reverse Engineering', 'danger', 500, 100, 713,
  '[DANGER — custom VM reversing] A licensing check runs inside a tiny custom stack VM. Given the opcode spec and the full disassembly, emulate its semantics to understand the per-character check — rotate_left8(input[i] XOR key[i], amt[i]) == ct[i] — then invert every block to recover the printable serial the VM accepts. Submit the serial exactly as recovered.',
  '/challenges/day7/vm-serial.txt', '/challenge/verify/d7_vm', 1, 7, true, true)
on conflict (id) do update set title=excluded.title, category=excluded.category,
  difficulty=excluded.difficulty, points=excluded.points, first_blood_bonus=excluded.first_blood_bonus,
  sort_order=excluded.sort_order, prompt=excluded.prompt, asset_url=excluded.asset_url,
  action_url=excluded.action_url, num_hints=excluded.num_hints, day=excluded.day,
  is_extra=excluded.is_extra, is_dynamic=excluded.is_dynamic;
insert into public.challenge_answer_keys (challenge_id, answer, secret, live_material) values ('d7_vm', 'cust0m_vm_pwn3d', encode(extensions.gen_random_bytes(16),'hex'), null)
  on conflict (challenge_id) do update set answer = excluded.answer, live_material = excluded.live_material;
insert into public.challenge_hints (challenge_id, hint_number, body, penalty) values ('d7_vm', 1, 'Each block is reversible: input[i] = rotate_right8(CMP_constant[i], ROL_amount[i]) XOR XOR_key[i]. Rebuild all 15 characters and you have the serial.', 60)
  on conflict (challenge_id, hint_number) do update set body = excluded.body, penalty = excluded.penalty;

insert into public.challenges (id, title, category, difficulty, points, first_blood_bonus, sort_order, prompt, asset_url, action_url, num_hints, day, is_extra, is_dynamic) values (
  'd7_mtp', 'Key Reuse', 'Cryptanalysis', 'danger', 525, 100, 714,
  '[DANGER — cryptanalysis] Twelve English messages were XOR-encrypted with the SAME keystream (a many-time pad). Key reuse is fatal: exploit it. Use the space-XOR / crib-dragging method across the twelve ciphertexts to recover the keystream column by column, decrypt the messages, and find the word_word_word_word phrase hidden in one of them. Submit that phrase (lowercase, underscores).',
  '/challenges/day7/many-time-pad.txt', '/challenge/verify/d7_mtp', 1, 7, true, true)
